import java.util.Map;
import java.util.LinkedHashMap;
import java.lang.StringBuilder;


public static String generateDynamicTable(Map dataMap) {
StringBuilder htmlBuilder = new StringBuilder();

htmlBuilder.append("<table style='width: 100%; border-collapse: collapse; font-family: Arial, sans-serif;'>");
htmlBuilder.append("<caption style='font-size: 16px; font-weight: bold; padding: 10px;'>Entitlement Information</caption>");
htmlBuilder.append("<thead>");
htmlBuilder.append("<tr style='background-color: #f2f2f2;'>");

// Column headers from keys
for (String key : dataMap.keySet()) {
htmlBuilder.append("<th style='border: 1px solid #ddd; padding: 8px;'>")
.append(key)
.append("</th>");
}

htmlBuilder.append("</tr>");
htmlBuilder.append("</thead>");
htmlBuilder.append("<tbody>");
htmlBuilder.append("<tr>");

// Row data from values
for (String value : dataMap.values()) {
htmlBuilder.append("<td style='border: 1px solid #ddd; padding: 8px;'>")
.append(value)
.append("</td>");
}

htmlBuilder.append("</tr>");
htmlBuilder.append("</tbody>");
htmlBuilder.append("</table>");

return htmlBuilder.toString();
}


Map data = new LinkedHashMap();
data.put("Entitlement Name", "Read Access");
data.put("Application Name", "Active Directory");
data.put("Value", "true");
data.put("Attribute Name", "PermissionLevel");
data.put("Attribute Type", "Boolean");

String html = generateDynamicTable(data);

return html;

