import sailpoint.object.*;
import java.util.regex.Pattern;

import sailpoint.object.QueryOptions;
import java.util.Iterator;
import sailpoint.object.Filter;
import sailpoint.object.Link;
import java.util.List; 
import java.util.ArrayList;


Identity identity = context.getObjectById(Identity.class, ownerIdentity);
String serviceIden = "";
String svcIden = "";
svcIden = "SVC_" + accountName.toUpperCase();
Identity serviceIdentity = context.getObjectByName(Identity.class, svcIden);
SailPointObject application = context.getObject(Application.class, "LDAP");
Pattern p = Pattern.compile("^[a-zA-Z0-9_-]*$");

if (accountName != null){
if (accountName.length() > 20) 
return "Account Name cannot exceed 20 characters.";

if (!(p.matcher(accountName).find())){ 
return "Account Name can only contain the following characters: a-z, A-Z, 0-9 and _";
}
if(accountName.toUpperCase().startsWith("RPA_")){
return "Account Name cannot starts with RPA_";
}
if(accountName.toUpperCase().startsWith("CLOUD-")){
return "Account Name cannot starts with CLOUD-";
}
if(serviceIdentity != null){
if(!serviceIdentity.getAdministrator().getName().equals(identity.getName()) && !serviceIdentity.getAdministrator().getName().equals("spadmin")){
return "The Identity for this account is currently owned by " + serviceIdentity.getAdministrator().getAttribute("micron_username") + ". Please select another account name or reach out to " + serviceIdentity.getAdministrator().getAttribute("micron_username")+" for ownership change of generic identity (refer iaghelp/).";
} else if (!serviceIdentity.getAdministrator().getName().equals(identity.getName()) && serviceIdentity.getAdministrator().getName().equals("spadmin")){
return "The selected account name is already in use for orphan generic accounts. Please select a new name, or assign the " + accountName + " ownership to the desired owner and try again.";
}
}
List iden = new ArrayList();
QueryOptions qo = new QueryOptions(); 

Filter f1 = Filter.eq("micron_username", accountName.toUpperCase());
qo.add(f1);
iden = context.getObjects(Identity.class, qo);
for (Identity searchIdentity : iden){
if(searchIdentity != null && searchIdentity != void){
if(searchIdentity.getAttribute("type") == null || !searchIdentity.getAttribute("type").equals("service")){
return searchIdentity.getAttribute("micron_username") + " is not a generic account, please choose another account name";
}
}
}
if(form.getSection("LDAP").getField("ldapApplication").getValue()!=true && form.getSection("activeDirectory").getField("selectDirectoryAccount").getValue()!=true && form.getSection("unix").getField("ldapUnixApplication").getValue()!=true){
return "Please select an application";
}
return null;
}

