import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;
import sailpoint.object.Application;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningTarget;
import sailpoint.object.Application;
import sailpoint.tools.GeneralException;
import sailpoint.object.ProvisioningProject;
import sailpoint.object.ProvisioningPlan;
import org.apache.log4j.Logger;
import sailpoint.object.ProvisioningTarget;
import sailpoint.object.WorkflowCase;

Logger log = Logger.getLogger("arm.workflow.ARMIntegrationLCMProvisioning");

log.debug("AR Project: " + project.toXml());
pplans = project.getPlans();
log.debug("pplans instantiated");
HashMap sapRoleNameRequestsBySystemId = new HashMap();
log.debug("roleRequests instantiated");
for (ProvisioningPlan pp : pplans) {
  String appName = pp.getTargetIntegration();
  Application app = context.getObjectByName(Application.class, appName);
  String armSystemId;
  if(app != null){
    armSystemId = app.getAttributeValue("armSystemId");
  } 
  log.debug("checking appName: " + appName);
  if (Util.isNotNullOrEmpty(armSystemId)) {
    log.debug("SAP System with ARM integration found - armSystemId: " + armSystemId);
    arequests = pp.getAccountRequests(appName);

    ArrayList sapRoleRequestsForOneSystem =new ArrayList();

    ArrayList sapRolesToAddForOneSystem = new ArrayList();
    sapRoleRequestsForOneSystem.add(0, sapRolesToAddForOneSystem);

    ArrayList sapRolesToRemoveForOneSystem = new ArrayList();
    sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);

    sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);

    for (AccountRequest arequest : arequests) {
      atrequests = arequest.getAttributeRequests();
      for (AttributeRequest atrequest : atrequests) {
        if (atrequest.getName().equals("Roles") && atrequest.getOp().toString().equals("Add")) {
          if ( atrequest.getValue() instanceof String) {

            if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
              //sapRoleRequestsForOneSystem = new ArrayList();
              //sapRolesToAddForOneSystem= new ArrayList();
              //sapRoleRequestsForOneSystem.add(0, sapRolesToAddForOneSystem);
              //sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
            } else { //if array list for this system id already exists we can assume that the add list in position 0 
              //already exists because of above code block
              sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
              sapRolesToAddForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(0);
            }
            String sapRoleName = (String) atrequest.getValue();
            sapRolesToAddForOneSystem.add(sapRoleName);
          } else {
            for (String atreq : atrequest.getValue()) {
              if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
                //sapRoleRequestsForOneSystem = new ArrayList();
                //sapRolesToAddForOneSystem= new ArrayList();
                //sapRoleRequestsForOneSystem.add(0, sapRolesToAddForOneSystem);
                //sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
              } else { //if array list for this system id already exists we can assume that the add list in position 0 
                //already exists because of above code block
                sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
                sapRolesToAddForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(0);
              }
              String sapRoleName = (String) atreq;
              sapRolesToAddForOneSystem.add(sapRoleName);
            }
          }
        } else if (atrequest.getName().equals("Roles") && atrequest.getOp().toString().equals("Remove")) {
          log.debug("atrequest.getValue(): " + atrequest.getValue());
          if ( atrequest.getValue() instanceof String) {

            if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
              //sapRoleRequestsForOneSystem = new ArrayList();
              //sapRolesToRemoveForOneSystem= new ArrayList();
              //sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
              //sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
            } else {
              sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
              //If size is two then we already have both a role add and role remove list added
              //therefore just append to existing remove roles list
              if(sapRoleRequestsForOneSystem.size()==2) {
                sapRolesToRemoveForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(1);
              } else { //else we have one entry we need to create the role remove list, 
                //if we had 0 entries the return for this system id would have been null and hit earlier if statement
                sapRolesToRemoveForOneSystem = new ArrayList();
                sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
              }
            }
            String sapRoleName = (String) atrequest.getValue();
            sapRolesToRemoveForOneSystem.add(sapRoleName);
          } else {
            for (String atreq : atrequest.getValue()) {
              if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
                //sapRoleRequestsForOneSystem = new ArrayList();
                //sapRolesToRemoveForOneSystem= new ArrayList();
                //sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
                //sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
              } else {
                sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
                //If size is two then we already have both a role add and role remove list added
                //therefore just append to existing remove roles list
                if(sapRoleRequestsForOneSystem.size()==2) {
                  sapRolesToRemoveForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(1);
                } else { //else we have one entry we need to create the role remove list, 
                  //if we had 0 entries the return for this system id would have been null and hit earlier if statement
                  sapRolesToRemoveForOneSystem = new ArrayList();
                  sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
                }
              }
              String sapRoleName = (String) atreq;
              sapRolesToRemoveForOneSystem.add(sapRoleName);
            }
          }
        }
      }
    }
  }
}
