private static String ARM_CUSTOMERID = AccessRiskManagementIntegrationPluginResource.getSettingValueFromPlugin(context,"AccessRiskManagementIntegrationPlugin","ARMCustomerId");			
private static String ARM_REPORT_URL = AccessRiskManagementIntegrationPluginResource.getSettingValueFromPlugin(context, "AccessRiskManagementIntegrationPlugin", "ARMReportingUrl");


String authToken = getAuthToken();

pplans = project.getPlans();

for (ProvisioningPlan pp : pplans) {
  String appName = pp.getTargetIntegration();

  Application app = context.getObjectByName(Application.class, appName);

  String armSystemId;
  if(app != null){
    armSystemId = app.getAttributeValue("armSystemId");
  } 

  System.out.println("arm System id : " + armSystemId);
  log.debug("arm System id : " + armSystemId);
  if (Util.isNotNullOrEmpty(armSystemId)) {
    arequests = pp.getAccountRequests(appName);
    ArrayList armRequestsForOneSystem = sapRoleNameRequestsBySystemId.get(armSystemId);
    System.out.println("armRequestsForOneSystem : " + armRequestsForOneSystem);
    log.debug("armRequestsForOneSystem : " + armRequestsForOneSystem);
    for (AccountRequest arequest : arequests) {
      atrequests = arequest.getAttributeRequests();
      //Roles to add are stored in position 0 and roles to remove are in position 1
      ArrayList sapRoleNamesToAdd = armRequestsForOneSystem.get(0);
      ArrayList sapRoleNamesToRemove;
      if(armRequestsForOneSystem.size()==2) {
        sapRoleNamesToRemove = armRequestsForOneSystem.get(1);
      }

      //We call different APIs depending on if the request is a modify and for a known system ID
      //or if it is a create request and therefore the SAP system ID is unkown to ARM at this point
      if(arequest.getOperation().equals(AccountRequest.Operation.Modify)) {
        String sapUserName = arequest.getNativeIdentity();

        String whatIfBackGroundJobId = performWhatIfBackgroundAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapUserName, sapRoleNamesToAdd, sapRoleNamesToRemove);
        JSONObject whatIfResponseJSON = performWhatIfRealTimeAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapUserName, sapRoleNamesToAdd, sapRoleNamesToRemove);

        System.out.println("What if response : " + whatIfResponseJSON.toString());
        log.debug("What if response : " + whatIfResponseJSON.toString());
        //JSONArray violations = (JSONArray) whatIfResponseJSON.get("violations");
        JSONArray violations = (!whatIfResponseJSON.isNull("violations"))?(JSONArray) whatIfResponseJSON.get("violations"):null;        

        if(violations != null && violations.length()>0) {

          for(int i =0; i<violations.length(); i++) {
            String description = "";

            JSONObject violation = (JSONObject) violations.get(i);
            String riskName = violation.getString("riskName");
            String ruleName = "Risk " + riskName + " was found on your request against the " + appName + " system.";
            String riskLevel = violation.getString("riskLevel");

            HashMap pv = new HashMap();

            pv.put("policyName", "ARM Analysis");

            pv.put("rightBundles", null);
            pv.put("leftBundles", null);

            pv.put("ruleName", ruleName);

            String riskType = violation.getString("riskType");

            //riskCode value is null if the user is a super user; the null check is needed
            String riskCode = (!violation.isNull("riskCode"))?violation.getString("riskCode"):"";
            String riskDescription = violation.getString("riskDescription");


            description += "\n Risk Code : " + riskCode;
            description += "\n Risk Name : " + riskName;	
            description += "\n Risk Level : " + riskLevel;
            description += "\n Risk Type : " + riskType;
            description += "\n Risk Description : " + riskDescription;
            JSONArray activities = violation.getJSONArray("activities");

            if(activities != null){
              ruleName += "Activities : ";
              for(int j=0; j<activities.length(); j++) {
                JSONObject activity = (JSONObject) activities.get(j);
                String functionCode = activity.getString("functionCode");
                String functionDescription = activity.getString("functionDescription");
                String functionName = activity.getString("functionName");
                description += "\n Function Name : " + functionName;
                description += "\n Function Code : " + functionCode;
                description += "\n Function Description : " + functionDescription;
              }						
            }
            description += " Enter the following link into your browser for detailed results : " + ARM_REPORT_URL + whatIfBackGroundJobId;

            pv.put("description", description);	
            policyViolations.add(pv);		


          }
        }

      } else if(arequest.getOperation().equals(AccountRequest.Operation.Create)) {
        //TODO : For when there is an API to do what if analysis when user id is new
        String whatIfBackGroundJobId = performWhatIfBackgroundNewUserAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapRoleNamesToAdd, sapRoleNamesToRemove);
        JSONObject whatIfResponseJSON = performWhatIfRealTimeNewUserAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapRoleNamesToAdd, sapRoleNamesToRemove);

        System.out.println("What if response : " + whatIfResponseJSON.toString());
        log.debug("What if response : " + whatIfResponseJSON.toString());
        //JSONArray violations = (JSONArray) whatIfResponseJSON.get("violations");
        JSONArray violations = (!whatIfResponseJSON.isNull("violations"))?(JSONArray) whatIfResponseJSON.get("violations"):null;        


        if(violations != null && violations.length()>0) {

          for(int i =0; i<violations.length(); i++) {
            String description = "";

            JSONObject violation = (JSONObject) violations.get(i);
            String riskName = violation.getString("riskName");
            String ruleName = "Risk " + riskName + " was found on your request against the " + appName + " system.";
            String riskLevel = violation.getString("riskLevel");

            HashMap pv = new HashMap();

            pv.put("policyName", "ARM Analysis");

            pv.put("rightBundles", null);
            pv.put("leftBundles", null);

            pv.put("ruleName", ruleName);

            String riskType = violation.getString("riskType");

            //riskCode value is null if the user is a super user; the null check is needed
            String riskCode = (!violation.isNull("riskCode"))?violation.getString("riskCode"):"";
            //String riskCode = violation.getString("riskCode");

            String riskDescription = violation.getString("riskDescription");


            description += "\n Risk Code : " + riskCode;
            description += "\n Risk Name : " + riskName;	
            description += "\n Risk Level : " + riskLevel;
            description += "\n Risk Type : " + riskType;
            description += "\n Risk Description : " + riskDescription;
            JSONArray activities = violation.getJSONArray("activities");

            if(activities != null){
              ruleName += "Activities : ";
              for(int j=0; j<activities.length(); j++) {
                JSONObject activity = (JSONObject) activities.get(j);
                String functionCode = activity.getString("functionCode");
                String functionDescription = activity.getString("functionDescription");
                String functionName = activity.getString("functionName");
                description += "\n Function Name : " + functionName;
                description += "\n Function Code : " + functionCode;
                description += "\n Function Description : " + functionDescription;
              }						
            }
            description += " Enter the following link into your browser for detailed results : " + ARM_REPORT_URL + whatIfBackGroundJobId;

            pv.put("description", description);	
            policyViolations.add(pv);		
          }
        }                  					   					
      }
    }
  }
}


return policyViolations;

