    protected String getSaltString(String saltChars, Integer size) {
    StringBuilder salt = new StringBuilder();
    Random rnd = new Random();
    while (salt.length() < size) { // length of the random string.
      int index = (int) (rnd.nextFloat() * saltChars.length());
      salt.append(saltChars.charAt(index));
    }
    String saltStr = salt.toString();
    return saltStr;
  }

  public String makePwd(){
    var passwd = "";

    passwd = passwd+getSaltString("ABCDEFGHJKLMNPQRSTUVWXYZ", 2);
    passwd = passwd+getSaltString("0123456789", 2);
    passwd = passwd+getSaltString("abcdefghjklmnpqrsuvwxyz", 2);
    passwd = passwd+getSaltString("!#@$%&", 2);
    passwd = passwd+getSaltString("ABCDEFGHJKLMNPQRSTUVWXYZ0123456789abcdefghjklmnpqrsuvwxyz!#@$%&", 4);   

    return passwd;
  }
