// Expect: List selectedTokens

import sailpoint.object.Identity;
import sailpoint.api.ObjectUtil;
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

Log logger = LogFactory.getLog("sailpoint.impersonatePlugin.workflow.revokeTokens.script.StepAction");

if (selectedTokens != null && !selectedTokens.isEmpty()) {
  logger.debug("Tokens to revoke: " + selectedTokens.toString());

  Identity identity = ObjectUtil.lockIdentity(context, identityName);
  if (identity != null) {
    try {
      Map preferences = identity.getPreferences();
      if (preferences == null) {
        logger.info("Creating new preferences map");
        preferences = new HashMap();
      }
      List impersonatePluginTokens = (List) preferences.get("impersonatePluginTokens");
      if (impersonatePluginTokens == null) {
        logger.info("Creating new token list");
        impersonatePluginTokens = new ArrayList();
      }

      List newImpersonatePluginTokens = new ArrayList();
      for (Map token: impersonatePluginTokens) {
        String tokenId = (String) token.get("id");
        if (tokenId != null && !selectedTokens.contains(tokenId)) {
          logger.debug("Keeping a non-selected token");
          newImpersonatePluginTokens.add(token);
        }
      }

      preferences.put("impersonatePluginTokens", newImpersonatePluginTokens);
      identity.setPreferences(preferences);
      logger.debug("Saving tokens");
      context.startTransaction();
      context.saveObject(identity);
      context.commitTransaction();
      logger.debug("Tokens saved");
    } finally {
      logger.debug("Unlock");
      ObjectUtil.unlockIdentity(context, identity); 
    }
  }
}

AfterScript.Source:
import sailpoint.object.Form;
import sailpoint.object.ProvisioningTarget;
import sailpoint.object.AccountSelection;
import sailpoint.object.Field;

Form accountSelectionForm = item.getForm();

Iterator fieldIterator = accountSelectionForm.iterateFields();

List targets = project.getProvisioningTargets();

//apply selected value to matching AccountSelection
//if accountSelectionId, then apply to the first unanswered AccountSelection
while (fieldIterator.hasNext()) {
    Field fld = (Field)fieldIterator.next();
    if (fld == null) 
      continue;

    Integer targetIndex = (Integer)fld.getAttribute("targetIndex");
    Integer selectionIndex = (Integer)fld.getAttribute("selectionIndex");

    if (targetIndex == null || selectionIndex == null) continue;

    ProvisioningTarget target = (ProvisioningTarget) targets.get(targetIndex.intValue());

    List selections = target.getAccountSelections();
    AccountSelection selection = (AccountSelection) selections.get(selectionIndex.intValue()); 

    if (selection.isAnswered()) continue;

    if (fld.getValue().equals("doCreateOpt")) {
      selection.setDoCreate(true);
    }
    else {
      selection.setSelection(fld.getValue());
    }
}

