if ( Util.isNotNullOrEmpty(workgroup) ) {
  Identity wg = context.getObjectByName(Identity.class, workgroup);
  Iterator itr = ObjectUtil.getWorkgroupMembers(context, wg, Arrays.asList("name"));
  while ( null != itr @and itr.hasNext() ) {
    String memberName = itr.next()[0];
    if ( null != memberName ) {
      Identity memberIdentity = context.getObjectByName(Identity.class, memberName);
      if (memberIdentity.isInactive() || (!isManagerExistInWG @and memberName.equals(managerName))) {
        memberIdentity.remove(wg);
        context.saveObject(memberIdentity);
      }
    }
  }
  // adding new member into workgroup
  Identity newOwnerIdentity = context.getObjectByName(Identity.class, newOwner);
  newOwnerIdentity.add(wg);
  context.saveObject(newOwnerIdentity);
  context.commitTransaction();
}

