import java.util.Map;
import java.util.HashMap;
import java.util.StringJoiner;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import com.google.gson.Gson;
import sailpoint.tools.GeneralException;

// Parse the access token from the response JSON
private static String parseBearerToken(String response) {
  String tokenPrefix = "\"access_token\":\"";
  int tokenStart = response.indexOf(tokenPrefix) + tokenPrefix.length();
  int tokenEnd = response.indexOf("\"", tokenStart);
  return response.substring(tokenStart, tokenEnd);
}

try {

  String clientId = "e358e084-76f7-424f-9138-fceb84e9b8be";
  String clientSecret = "Vi18Q~zewKxrSZJNVWcpyvLexHovtCLwI-UgfalT";
  String tenantId = "af207c52-e79d-46ba-9fae-c5da532b61f6";
  String tokenUrl = "https://login.microsoftonline.com/" + tenantId + "/oauth2/v2.0/token";
  String domain = "@eshiamsoftware.onmicrosoft.com";

  String body = new StringJoiner("&")
    .add("grant_type=client_credentials")
    .add("client_id=" + clientId)
    .add("client_secret=" + clientSecret)
    .add("scope=https://graph.microsoft.com/.default")
    .toString();

  HttpRequest tokenRequest = HttpRequest.newBuilder()
    .uri(URI.create(tokenUrl))
    .header("Content-Type", "application/x-www-form-urlencoded")
    .POST(HttpRequest.BodyPublishers.ofString(body))
    .build();

  HttpClient client = HttpClient.newHttpClient();
  HttpResponse<String> tokenResponse = client.send(tokenRequest, HttpResponse.BodyHandlers.ofString());

  if (tokenResponse.statusCode() == 200) {

    String accessToken = parseBearerToken(tokenResponse.body());
    String graphUrl = "https://graph.microsoft.com/v1.0/users";

    Map payload = new HashMap();
    payload.put("accountEnabled", true);
    payload.put("displayName", identityModel.get("displayName"));
    payload.put("mailNickname", identityModel.get("name"));
    payload.put("userPrincipalName", identityModel.get("name") + domain);

    workflow.put("name", identityModel.get("name"));
    workflow.put("userPrincipalName", identityModel.get("name") + domain);
    workflow.put("displayName", identityModel.get("displayName"));

    Map passwordProfile = new HashMap();
    passwordProfile.put("forceChangePasswordNextSignIn", true);
    passwordProfile.put("password", identityModel.get("password"));
    payload.put("passwordProfile", passwordProfile);

    Gson gson = new Gson();
    String jsonPayload = gson.toJson(payload);

    // Create a POST request to create a user
    HttpRequest request = HttpRequest.newBuilder()
      .uri(URI.create(graphUrl))
      .header("Authorization", "Bearer " + accessToken)
      .header("Content-Type", "application/json")
      .POST(HttpRequest.BodyPublishers.ofString(jsonPayload))
      .build();

    HttpClient client = HttpClient.newHttpClient();
    HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

    if (response.statusCode() == 201) {
      log.info("User created successfully: " + response.body());
    } else {
      log.error("Error: " + response.statusCode());
      log.error("Response Body: " + response.body());
    }
  }
} catch (GeneralException e) {
  throw new GeneralException("GeneralException occured when try to connect microsoft graph api." + e.getMessage());
}

