import sailpoint.tools.Util;

String APP_NAME = "Mexichem-Application-AzureActiveDirectory";

ProvisioningPlan plan = new ProvisioningPlan();
ObjectRequest or = new ObjectRequest();
or.setOp(ProvisioningPlan.ObjectOperation.Modify);

if ( Util.isNotNullOrEmpty(entitlementSource) && entitlementSource.contains("Azure") ) {

  String azureADDomain = "c9d68b56-8bd5-4240-b03a-ee7e260a3bf0";
  String clientID = "a7a47b44-8c6a-4e7e-a008-b8352cd47f62";
  String clientSecret = "OUa8Q~E~Hkc1fLXohPC8tXA5_FxsXUk7t9FgecWq";
  //String upn = "TestMobile@orbiadev.onmicrosoft.com";

  String tokenUrl = "https://login.microsoftonline.com/" + azureADDomain + "/oauth2/v2.0/token";

  HttpClient httpClient = HttpClient.newBuilder().build(); // Create a single HttpClient for all requests

  // First request to obtain an access token
  String urlEncoded = "scope=https://graph.microsoft.com/.default" + "&client_id=" + clientID + "&client_secret=" + clientSecret + "&grant_type=client_credentials";

  HttpRequest tokenRequest = HttpRequest.newBuilder()
    .POST(HttpRequest.BodyPublishers.ofString(urlEncoded))
    .uri(URI.create("https://login.microsoftonline.com/" + azureADDomain + "/oauth2/v2.0/token"))
    .header("Content-Type", "application/x-www-form-urlencoded")
    .build();

  HttpResponse<String> tokenResponse = httpClient.send(tokenRequest, HttpResponse.BodyHandlers.ofString());

  Map responseMap = (Map) JsonUtil.parse(tokenResponse.body());
  String accessToken = (String) responseMap.get("access_token");

  if (Util.isNullOrEmpty(accessToken)) {
    log.error("Failed to retrieve access token. Response body: " + tokenResponse.body());
    throw new RuntimeException("Access token is missing or invalid.");
  } else {
    log.error("Access token retrieved successfully.");
  }

  if (!accessToken.contains(".")) {
    log.error("Access token format is invalid. JWT must contain three parts separated by dots.");
    throw new RuntimeException("Invalid JWT format in access token.");
  }

  if ( source.equalsIgnoreCase("SCIM") ) {
    entitlementDisplayName = entitlementName; // SCIM REST API Call
  }

  if (Util.isNotNullOrEmpty(entitlementDisplayName)) {
    Filter maFilter = Filter.and(Filter.eq("application.name", APP_NAME), Filter.eq("displayName", entitlementDisplayName), Filter.eq("type", "group"), Filter.eq("attribute", "groups"));
    ManagedAttribute managedAttribute = context.getUniqueObject(ManagedAttribute.class, maFilter);
    if ( managedAttribute != null ) {
      String nativeIdentity = managedAttribute.getNativeIdentity();
      String groupUrl = "https://graph.microsoft.com/v1.0/groups/" + nativeIdentity;
      workflow.put("nativeIdentity", nativeIdentity);

      JSONObject groupPayload = new JSONObject();
      if (entitlementDescription != null) groupPayload.put("description", entitlementDescription);
      if (entitlementDisplayName != null) {
        groupPayload.put("displayName", entitlementDisplayName);
      }

      HttpRequest groupRequest = HttpRequest.newBuilder()
        .method("PATCH", HttpRequest.BodyPublishers.ofString(groupPayload.toString()))
        .uri(URI.create(groupUrl))
        .header("Authorization", "Bearer " + accessToken)
        .header("Content-Type", "application/json")
        .build();

      HttpResponse<String> groupResponse = httpClient.send(groupRequest, HttpResponse.BodyHandlers.ofString());
      workflow.put("entitlementDisplayName", entitlementDisplayName);
      workflow.put("statusCode", groupResponse.statusCode());
    }
  }
} else {        

  if (Util.isNotNullOrEmpty(entitlementSource) && !entitlementSource.contains("Azure") && source.equalsIgnoreCase("UI")) {
    entitlementDisplayName = entitlementName.split(",")[0].split("CN=")[1];     
  } else if (source.equalsIgnoreCase("SCIM")) {
    entitlementDisplayName = entitlementName;
    workflow.put("entitlementDisplayName", entitlementDisplayName);
  }

  String dn = null;
  Custom custom = context.getObjectByName(Custom.class, "Custom-GroupMappings");
  Map domainMap = (Map) custom.get(domain);
  String dnPath = (String) domainMap.get("ou");
  dn = "CN=" + entitlementDisplayName + dnPath;
  or.setType("group");
  APP_NAME = (String) domainMap.get("appName");

  workflow.put("applicationName", APP_NAME);
  workflow.put("nativeIdentity", dn);

  or.setNativeIdentity(dn);
  or.add(new AttributeRequest("sAMAccountName", ProvisioningPlan.Operation.Add, entitlementDisplayName));
  or.add(new AttributeRequest("cn", ProvisioningPlan.Operation.Add, entitlementDisplayName));
  or.add(new AttributeRequest("distinguishedName", ProvisioningPlan.Operation.Add, dn));
  or.add(new AttributeRequest("GroupType", ProvisioningPlan.Operation.Add, "Security"));
  or.add(new AttributeRequest("GroupScope", ProvisioningPlan.Operation.Add, "Global"));
  or.add(new AttributeRequest("objectClass", ProvisioningPlan.Operation.Add, "group"));
  or.add(new AttributeRequest("description", ProvisioningPlan.Operation.Set, entitlementDescription));

  HashMap descriptions = new HashMap();
  descriptions.put("en_US", entitlementDescription);
  or.add(new AttributeRequest("sysDescriptions", ProvisioningPlan.Operation.Set, descriptions));
  or.setApplication(APP_NAME);
  plan.addObjectRequest(or);
  workflow.put("plan", plan);
  return plan;
}


