/*
      *
      * Helper Methods
      *
      */

private Identity getIdentityObject(String identityName) {
  if ( Util.isNotNullOrEmpty(identityName)) {
    if ( identityName.contains("@") ) {
      List idList = ObjectUtil.getIdentitiesToNotifyFromEmail(context, identityName);
      if ( Util.nullSafeSize(idList) == 1 ) return idList.get(0);
    } else {
      return context.getObject(Identity.class, identityName);
    }
    return null;
  }
}

private boolean isMemberExistInWG(String workgroupName, String identityNameOrId) {
  if ( Util.isNotNullOrEmpty(workgroupName) && Util.isNotNullOrEmpty(identityNameOrId) ) {
    Identity identity = getIdentityObject(identityNameOrId);
    if ( identity == null ) {
      throw new IllegalArgumentException("Identity not found with " + identityNameOrId); 
    }
    Filter filter = Filter.and(Filter.eq("workgroups.name", workgroupName), Filter.eq("id", identity.getId()));
    QueryOptions qo = new QueryOptions();
    qo.add(filter);
    qo.setResultLimit(1);
    return context.countObjects(Identity.class, qo) > 0 ? true : false;
  }
  return false;
}

private void addMembersToWorkGroup(String workGroupName, String identityName) {
  if (Util.isNotNullOrEmpty(workGroupName) && Util.isNotNullOrEmpty(identityName)) {
    Identity workGroup = context.getObject(Identity.class, workGroupName);
    if ( null != workGroup && workGroup.isWorkgroup()) {
      Identity memberIdentity = getIdentityObject(identityName);
      if ( memberIdentity != null ) memberIdentity.add(workGroup);
      context.saveObject(memberIdentity);
      context.commitTransaction();
    }
  }
}

private void removeMembersFromWorkGroup(String workGroupName, String identityName) {
  if (Util.isNotNullOrEmpty(workGroupName) && Util.isNotNullOrEmpty(identityName)) {
    Identity workGroup = context.getObject(Identity.class, workGroupName);
    if ( null != workGroup && workGroup.isWorkgroup()) {
      Identity memberIdentity = getIdentityObject(identityName);
      if ( memberIdentity != null ) memberIdentity.remove(workGroup);
      context.saveObject(memberIdentity);
      context.commitTransaction();
    }
  }
}

private List getWorkGroupMembers(String workgroupName) {
  List existingMembersList = new ArrayList();
  if ( Util.isNotNullOrEmpty(workgroupName) ) {
    Identity workGroup = context.getObjectByName(Identity.class, workgroupName);
    Iterator itr = ObjectUtil.getWorkgroupMembers(context, workGroup, null);
    while (null != itr && itr.hasNext()) {
      Object[] object = (Object[]) itr.next();
      if ( null != object ) {
        Identity memberIdentity = (Identity) object[0];
        existingMembersList.add(memberIdentity.getId());
      }
    }
  }
  return existingMembersList;
}

private List convertEmailsToIds(List emailAddresses) {
  List identityIds = new ArrayList();
  for (String part : Util.safeIterable(emailAddresses)) {
    List idList = ObjectUtil.getIdentitiesToNotifyFromEmail(context, part.trim());
    if ( Util.nullSafeSize(idList) == 1 ) identityIds.add(idList.get(0).getName());
  }
  return ObjectUtil.convertToIds(context, Identity.class, identityIds);;
}

/*
      *
      * Main Code Start Here.
      *
      */

String APP_NAME = null;
ManagedAttribute ma = null;

if ( Util.isNotNullOrEmpty(entitlementSource) && entitlementSource.contains("Azure") ) {
  APP_NAME = "Mexichem-Application-AzureActiveDirectory";
} else if (Util.isNotNullOrEmpty(applicationName) ) {
  APP_NAME = applicationName;
}

if ( Util.isNotNullOrEmpty(APP_NAME) && Util.isNotNullOrEmpty(entitlementDisplayName) ) {
  Filter maFilter = Filter.and(Filter.eq("application.name", APP_NAME), Filter.eq("displayName", entitlementDisplayName));
  ma = context.getUniqueObject(ManagedAttribute.class, maFilter);        
}        

if ( null != ma ) {
  Identity oldEntitlementOwner = ma.getOwner();
  ma.setDisplayName(entitlementDisplayName);

  if ( Util.isNotNullOrEmpty(governanceLevel) ) {
    Pattern pattern = Pattern.compile("GL(\\d{2})");
    Matcher matcher = pattern.matcher(governanceLevel);
    if (matcher.find()) {
      String number = matcher.group(1); // Extract the number part (01, 02, etc.)
      int num = Integer.parseInt(number);  // Convert "01" to "1", "02" to "2"
      String glvl = "GL" + num;
      // ma.setAttribute("governanceLevel", glvl);
    }
    String suffix = " approval required";
    if (governanceLevel.contains(suffix)) {
      governanceLevel = governanceLevel.substring(0, governanceLevel.length() - suffix.length());
    }
    if (governanceLevel.contains("GL00")) {
      governanceLevel = "GL00 - Auto";
    }
  }

  if (governanceLevel.contains("GL04")) {
    ma.setAttribute("additionalEntBusApprovers", "WG-ADandAzureOwner"); 
  }

  workflow.put("governanceLevel", governanceLevel); // override form governanceLevel value to new governanceLevel value
  ma.setAttribute("manualOverride", manualOverride);
  if ( governanceLevel != null ) ma.setAttribute("approvalMode", governanceLevel);
  if ( entitlementDescription != null ) ma.setAttribute("description", entitlementDescription);

  Identity ownerIdentity = null;
  if (entitlementOwner.contains("@")) {
    Filter emailFilter = Filter.eq("email", entitlementOwner);
    ownerIdentity = context.getUniqueObject(Identity.class, emailFilter);
    ma.setOwner(ownerIdentity);
  } else {
    ownerIdentity = context.getObject(Identity.class, entitlementOwner);
    ma.setOwner(ownerIdentity);
  }
  String entBusinessApprover = ma.getAttribute("entBusApprovers");
  if (Util.isNotNullOrEmpty(entitlementSource) && !entitlementSource.contains("Azure") && source.equalsIgnoreCase("UI")) {
    entitlementDisplayName = entitlementName.split(",")[0].split("CN=")[1];
  } else if (source.equalsIgnoreCase("SCIM")) {
    entitlementDisplayName = entitlementName;
  }
  if ((Util.isNullOrEmpty(entBusinessApprover) || Util.isNotNullOrEmpty(entBusinessApprover)) && Util.isNotNullOrEmpty(entitlementDisplayName)) {
    String workgroupName = "WG-Approver-" + entitlementDisplayName;
    Identity workgroupIdentity = context.getObjectByName(Identity.class, workgroupName);
    if ( workgroupIdentity == null ) {
      workgroupIdentity = new Identity();
      workgroupIdentity.setName(workgroupName);
      workgroupIdentity.setWorkgroup(true);
      context.saveObject(workgroupIdentity);
    }
    workflow.put("workGroupName", workgroupName);
    entBusinessApprover = workgroupName;
    ma.setAttribute("entBusApprovers", entBusinessApprover);
  }        

  if ( null != workGroupApprovers && workGroupApprovers instanceof String && workGroupApprovers.contains("@") ) {
    List<String> approvers = new ArrayList();
    String jsonArrayStr = workGroupApprovers; // It's a string
    JSONArray jsonArray = new JSONArray(jsonArrayStr);
    for (int i = 0; i < jsonArray.length(); i++) {
      approvers.add(jsonArray.getString(i));
    }
    workGroupApprovers = convertEmailsToIds(approvers);
  }

  List newMembersList = new ArrayList(workGroupApprovers);
  List existingMembersList = getWorkGroupMembers(entBusinessApprover);

  List updatedMembersList = new ArrayList(newMembersList);
  updatedMembersList.removeAll(existingMembersList);        

  List removeableMembersList = new ArrayList(newMembersList);
  removeableMembersList.removeAll(updatedMembersList);

  List updatedRemoveAbleMembersList = new ArrayList(existingMembersList);
  updatedRemoveAbleMembersList.removeAll(removeableMembersList);

  if (!isMemberExistInWG(entBusinessApprover, entitlementOwner)) {
    addMembersToWorkGroup(entBusinessApprover, entitlementOwner);
  }

  // add members to workgroup
  if ( Util.nullSafeSize(updatedMembersList) > 0 ) {
    for ( String identityName : updatedMembersList ) {
      if (!isMemberExistInWG(entBusinessApprover, identityName)) {
        addMembersToWorkGroup(entBusinessApprover, identityName);
      }
    }
  }

  // remove members from workgroup
  if ( Util.nullSafeSize(updatedRemoveAbleMembersList) > 0 ) {
    for ( String identityName : updatedRemoveAbleMembersList ) {
      if (isMemberExistInWG(entBusinessApprover, identityName)) {
        removeMembersFromWorkGroup(entBusinessApprover, identityName);
      }
    }
  } else if (Util.isNotNullOrEmpty(governanceLevel) && (governanceLevel.contains("GL00") || governanceLevel.contains("GL01"))) { // remove members from workgroup when governance level is GL00 or GL01
    if ( Util.nullSafeSize(removeableMembersList) > 0 ) {
      for ( String identityName : removeableMembersList ) {
        if (isMemberExistInWG(entBusinessApprover, identityName)) {
          removeMembersFromWorkGroup(entBusinessApprover, identityName);
        }
      }
    }
  }

  if ( oldEntitlementOwner != null && !oldEntitlementOwner.getId().equals(entitlementOwner.contains("@") ? getIdentityObject(entitlementOwner).getId() : entitlementOwner) ) {
    removeMembersFromWorkGroup(entBusinessApprover, oldEntitlementOwner.getId());
  }

  // add an entitlement owner to workgroup
  addMembersToWorkGroup(entBusinessApprover, entitlementOwner);

  context.saveObject(ma);
  context.commitTransaction();
}


