  Filter emailFilter = Filter.eq("email", entitlementOwner);
  entOwnerId = context.getUniqueObject(Identity.class, emailFilter);
} else if (Util.isNotNullOrEmpty(entitlementOwner)) {
  entOwnerId = context.getObject(Identity.class, entitlementOwner);
}
if ( null != entOwnerId ) {
  String oname = entOwnerId.getDisplayName();
  String oemail = entOwnerId.getEmail();
  EmailTemplate template = (EmailTemplate)context.getObject(EmailTemplate.class, "Orbia-EmailTemplate-UpdateGroup");
  if ( template == null ) {
    log.error("Email Template should not be null or Empty");
  }
  Map mailArgs = new HashMap();
  mailArgs.put("domain", domain);
  mailArgs.put("entitlementName", entitlementDisplayName);
  mailArgs.put("entitlementSource", entitlementSource);
  mailArgs.put("entitlementOwner", oname);
  mailArgs.put("entitlementOwnerEmail", oemail);
  mailArgs.put("governanceLevel", governanceLevel);
  List workGroupApproversEmails = ObjectUtil.getEffectiveEmails(context, context.getObject(Identity.class, workGroupName));        
  if ( Util.nullSafeSize(workGroupApproversEmails) > 0 ) {     
  	mailArgs.put("workGroupApproversEmails", String.join(", ", workGroupApproversEmails));
  }
  mailArgs.put("whenTriggered", getDate());
  String toEmail = entOwnerId.getEmail();
  //String toEmail = "harpreet_singh.ext@orbia.com";
  EmailOptions options = new EmailOptions(toEmail, mailArgs);
  //options.setTo("harpreet_singh.ext@orbia.com");
  options.setTo(entOwnerId.getEmail());
  //options.setSendImmediate(true);
  //options.setNoRetry(true);
  context.sendEmailNotification(template, options);
}

