AfterScript.Source:
import sailpoint.tools.Util;
import sailpoint.object.Identity;
import sailpoint.object.WorkItem;

log.error("status:: " + status);
try {
  Identity id = context.getObjectByName(Identity.class, identityName);
  if (item != null && item.getState() == WorkItem.State.Finished) {
    if (Util.isNotNullOrEmpty(deputyApprover)) {
      id.setAttribute("deputyApprover", deputyApprover);
    }
    if (Util.isNotNullOrEmpty(alternativeApprover)) {
      Identity altId = context.getObjectByName(Identity.class, alternativeApprover);
      if (altId != null && Util.isNotNullOrEmpty(altId.getEmail())) {
        id.setAttribute("alternativeApprover", altId.getEmail());
      }
    }
    context.saveObject(id);
    context.commitTransaction();
  } else if (optout != null && Util.otob(optout)) {
    id.setAttribute("deputyApprover", identityName);
    String email = id.getEmail();
    if (Util.isNotNullOrEmpty(email)) {
      id.setAttribute("alternativeApprover", email);
    }
    context.saveObject(id);
    context.commitTransaction();
  } else if (item != null && item.getState() == WorkItem.State.Expired) {
    String execLevel = item.getAttribute("executiveLevel");
    if (!Util.nullSafeCaseInsensitiveEq(execLevel, "VP")) {
      String deputy = id.getAttribute("deputyApprover");
      String alt = id.getAttribute("alternativeApprover");
      String email = id.getEmail();
      boolean changed = false;
      if (Util.isNullOrEmpty(deputy) && Util.isNullOrEmpty(alt)) {
        id.setAttribute("deputyApprover", identityName);
        if (Util.isNotNullOrEmpty(email)) {
          id.setAttribute("alternativeApprover", email);
        }
        changed = true;
      } else if (Util.isNotNullOrEmpty(deputy) && Util.isNullOrEmpty(alt)) {
        if (Util.isNotNullOrEmpty(email)) {
          id.setAttribute("alternativeApprover", email);
          changed = true;
        }
      } else if (Util.isNullOrEmpty(deputy) && Util.isNotNullOrEmpty(alt)) {
        id.setAttribute("deputyApprover", identityName);
        changed = true;
      }
      if (changed) {
        context.saveObject(id);
        context.commitTransaction();
      }
    }
  }
} catch (Exception e) {
  log.error("Error in AfterScript: " + e.getMessage());
}

